// Flatten each GTW webinar to the match fields. Native 'Webinar: Get All'
// returns one item per webinar; first session's startTime is the event date.
return $input.all().map((it) => {
  const w = it.json;
  const t0 = (w.times && w.times[0]) || {};
  const start = t0.startTime || w.startTime || null;
  return { json: {
    webinar_key: String(w.webinarKey || w.id || ''),
    subject: w.subject || w.name || null,
    time_zone: w.timeZone || null,
    start_time: start,
    start_date: start ? String(start).slice(0, 10) : null,
    session_count: Array.isArray(w.times) ? w.times.length : null
  }};
});

// Slim SF webinar campaigns + parse the webinar date from the name.
//   sf_start_date / sf_end_date = Campaign.StartDate/EndDate (StartDate is the
//     campaign WINDOW-OPEN date, NOT the webinar date — confirmed 0/4 match).
//   name_date = dd.mm.yyyy in Campaign.Name -> yyyy-mm-dd (DAY-FIRST), the real
//     webinar date; name_date_raw kept for audit.
function nameDate(name) {
  const m = String(name || '').match(/(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{4})/);
  if (!m) return { raw: null, iso: null };
  const dd = m[1].padStart(2, '0'), mm = m[2].padStart(2, '0');
  return { raw: m[0], iso: `${m[3]}-${mm}-${dd}` };
}
return $input.all().map((it) => {
  const c = it.json;
  const nd = nameDate(c.Name);
  return { json: {
    campaign_key: c.Id,
    name: c.Name || null,
    status: c.Status || null,
    sf_start_date: c.StartDate || null,
    sf_end_date: c.EndDate || null,
    name_date_raw: nd.raw,
    name_date: nd.iso
  }};
});

// Match GTW webinars <-> SF webinar campaigns. Join key confirmed from live data
// (20 Jun): Campaign.StartDate == GTW date matches 0/4; name-date matches 3/4 exact;
// the 4th (no date in name) resolves uniquely by title + GTW date in [StartDate,EndDate].
const gtw = $('Flatten GTW').all().map((i) => i.json);
const sf = $('Slim SF').all().map((i) => i.json);

// 1) drop GTW dry-runs / run-throughs / tests
const DRY = /\b(dry[\s-]?run|run[\s-]?through|rehearsal|\btest\b)\b/i;
const live = gtw.filter((w) => !DRY.test(w.subject || ''));
const droppedDryRuns = gtw.length - live.length;

// title token-overlap for tie-breaks / nameless fallback
function toks(s) { return new Set(String(s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).filter((w) => w.length > 3)); }
function overlap(a, b) { const A = toks(a), B = toks(b); if (!A.size || !B.size) return 0; let n = 0; for (const t of A) if (B.has(t)) n++; return n / Math.min(A.size, B.size); }

const out = [];
const usedGtw = new Set();

for (const c of sf) {
  let best = null, reason = '';

  // PRIMARY: name-date == GTW start_date
  if (c.name_date) {
    const cands = live.filter((w) => w.start_date === c.name_date && !usedGtw.has(w.webinar_key));
    if (cands.length === 1) { best = cands[0]; reason = 'name-date == GTW date'; }
    else if (cands.length > 1) { best = cands.slice().sort((a, b) => overlap(b.subject, c.name) - overlap(a.subject, c.name))[0]; reason = 'name-date == GTW date (+title tiebreak)'; }
  }

  // FALLBACK: title overlap + GTW date within [StartDate, EndDate]
  if (!best) {
    const inWin = live.filter((w) => !usedGtw.has(w.webinar_key) && c.sf_start_date && c.sf_end_date && w.start_date >= c.sf_start_date && w.start_date <= c.sf_end_date);
    const ranked = inWin.map((w) => ({ w, score: overlap(w.subject, c.name) })).sort((a, b) => b.score - a.score);
    if (ranked.length && ranked[0].score >= 0.34) { best = ranked[0].w; reason = 'title + GTW date in [StartDate,EndDate]'; }
  }

  if (best) {
    usedGtw.add(best.webinar_key);
    out.push({ json: {
      matched: true,
      match_reason: reason,
      campaign_key: c.campaign_key,
      sf_name: c.name,
      sf_start_date: c.sf_start_date,   // campaign window-open (NOT the webinar date)
      sf_end_date: c.sf_end_date,
      name_date: c.name_date,           // webinar date parsed from the name
      webinar_key: best.webinar_key,
      gtw_subject: best.subject,
      gtw_start_date: best.start_date,
      gtw_time_zone: best.time_zone
    }});
  } else {
    out.push({ json: { matched: false, side: 'sf_unmatched', campaign_key: c.campaign_key, sf_name: c.name, sf_start_date: c.sf_start_date, name_date: c.name_date, note: 'no GTW webinar matched' }});
  }
}

// surface any live GTW webinars that didn't match an SF campaign (visibility, not an error)
for (const w of live) {
  if (!usedGtw.has(w.webinar_key)) out.push({ json: { matched: false, side: 'gtw_unmatched', webinar_key: w.webinar_key, gtw_subject: w.subject, gtw_start_date: w.start_date } });
}

const matched = out.filter((r) => r.json.matched).length;
out.unshift({ json: { _summary: true, sf_campaigns: sf.length, gtw_total: gtw.length, gtw_dry_runs_dropped: droppedDryRuns, gtw_live: live.length, matched, sf_unmatched: out.filter((r) => r.json.side === 'sf_unmatched').length, gtw_unmatched: out.filter((r) => r.json.side === 'gtw_unmatched').length } });
return out;
